def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.dml.color import RGBColor
    import os
    # Define what is considered 'light blue' in RGB
    LIGHT_BLUE_RGB = [
        (173, 216, 230), # LightBlue
        (135, 206, 250), # LightSkyBlue
        (176, 224, 230), # PowderBlue
        (0, 191, 255),   # DeepSkyBlue
        (135, 206, 235)  # SkyBlue
    ]
    TOLERANCE = 20 # Accept a range for minor agent imprecision

    if not os.path.exists(modified_ppt_path):
        return ("Modified PPT file not found.", 0.0)
    try:
        prs = Presentation(modified_ppt_path)
        slide = prs.slides[2] # slide 3 is index 2
        bg = slide.background
        # Try to get fill color
        if not bg.fill or bg.fill.type != 1:
            return ("Slide 3 background does not have a solid fill.", 0.0)
        color = bg.fill.fore_color.rgb
        if color is None:
            return ("Slide 3 background color not detected.", 0.0)
        r, g, b = color[0], color[1], color[2]
        for lbr, lbg, lbb in LIGHT_BLUE_RGB:
            if abs(r-lbr)<=TOLERANCE and abs(g-lbg)<=TOLERANCE and abs(b-lbb)<=TOLERANCE:
                return ("Slide 3 background color is light blue.", 1.0)
        return (f"Slide 3 background color is not light blue. Detected RGB: ({r},{g},{b})", 0.0)
    except Exception as e:
        return (f"Error checking background color: {e}", 0.0)

